css:
:root {
   --page-width: 210mm;
   --page-height: 297mm;
   --pad-x: 18mm;
   --pad-top: 15mm;
   --pad-bottom: 14mm;
   --brand: #2a63ad;
   --brand-soft: #dce8f7;
   --brand-faint: #eff5fc;
   --ink: #404040;
   --muted: #7b7b7b;
   --line: #d7dde7;
   --paper: #ffffff;
   --shadow: 0 18px 44px rgba(29, 49, 79, 0.14);
   --font-main: "Arial", "Helvetica Neue", sans-serif;
   --font-head: "Arial", "Helvetica Neue", sans-serif;
 }

 * {
   box-sizing: border-box;
 }

 html,
 body {
   margin: 0;
   padding: 0;
   background: #edf2f8;
   color: var(--ink);
   font-family: var(--font-main);
 }

 body {
   padding: 18px 0 40px;
 }

 .document {
   width: var(--page-width);
   margin: 0 auto;
 }

 .page {
   position: relative;
   width: var(--page-width);
   min-height: var(--page-height);
   margin: 0 auto 18px;
   background: var(--paper);
   box-shadow: var(--shadow);
   page-break-after: always;
   overflow: hidden;
 }

 .page-inner {
   padding: var(--pad-top) var(--pad-x) var(--pad-bottom);
   min-height: var(--page-height);
   position: relative;
 }

 .cover .page-inner {
   display: flex;
   flex-direction: column;
   gap: 12mm;
 }

 .top-band {
   position: absolute;
   inset: 0 0 auto 0;
   height: 6mm;
   background: var(--brand);
 }

 .bottom-band {
   position: absolute;
   inset: auto 0 0 0;
   height: 5mm;
   background: linear-gradient(90deg, var(--brand) 0 78%, #b9cde8 78% 100%);
 }

 .page-header,
 .page-footer,
 .cover-meta,
 .cover-signature,
 .contact-row {
   display: flex;
   align-items: flex-start;
   justify-content: space-between;
   gap: 10mm;
 }

 .page-header,
 .page-footer {
   font-size: 9pt;
   color: var(--brand);
 }

 .page-footer {
   position: absolute;
   left: var(--pad-x);
   right: var(--pad-x);
   bottom: 7mm;
   align-items: center;
 }

 .footer-left {
   max-width: 110mm;
   line-height: 1.25;
 }

 .page-number {
   white-space: nowrap;
   font-weight: 700;
 }

 .brand-line {
   font-size: 9pt;
   color: var(--brand);
   line-height: 1.2;
 }

 .cover-city {
   font-size: 10pt;
   color: var(--muted);
 }

 .recipient-card {
   align-self: flex-end;
   width: 70mm;
   padding: 5mm 5.5mm;
   border: 1px solid var(--line);
   background: #fafcff;
 }

 .label {
   font-size: 8pt;
   text-transform: uppercase;
   letter-spacing: 0.08em;
   color: var(--muted);
   margin-bottom: 2mm;
 }

 .recipient-card strong,
 .meta-card strong,
 .sign-name {
   display: block;
   font-size: 12pt;
   color: #202020;
 }

 h1,
 h2,
 h3,
 p {
   margin: 0;
 }

 h1 {
   font-family: var(--font-head);
   font-size: 22pt;
   line-height: 1.12;
   color: var(--brand);
   letter-spacing: -0.01em;
   text-transform: uppercase;
   max-width: 128mm;
 }

 h2 {
   font-family: var(--font-head);
   font-size: 14pt;
   line-height: 1.2;
   color: var(--brand);
   margin-bottom: 3.5mm;
   text-transform: uppercase;
 }

 h3 {
   font-size: 10pt;
   line-height: 1.2;
   color: var(--brand);
   text-transform: uppercase;
   margin-bottom: 2.6mm;
 }

 .lead,
 .text,
 .cover-text,
 .footer-left,
 .list,
 .table,
 .grid-note {
   font-size: 10pt;
   line-height: 1.42;
 }

 .cover-text {
   max-width: 154mm;
   line-height: 1.5;
   text-align: justify;
 }

 .lead,
 .text {
   text-align: justify;
 }

 .cover-company {
   display: grid;
   grid-template-columns: 1fr 64mm;
   gap: 8mm;
   align-items: start;
 }

 .company-box {
   border-left: 3mm solid var(--brand);
   padding-left: 5mm;
 }

 .service-list,
 .bullet-list,
 .dash-list,
 .link-list {
   margin: 0;
   padding: 0;
   list-style: none;
 }

 .service-list li,
 .bullet-list li,
 .dash-list li,
 .link-list li {
   position: relative;
   padding-left: 5mm;
   margin-bottom: 2mm;
   font-size: 10pt;
   line-height: 1.35;
 }

 .service-list li::before,
 .bullet-list li::before,
 .dash-list li::before,
 .link-list li::before {
   content: "";
   position: absolute;
   left: 0;
   top: 5px;
   width: 2.3mm;
   height: 2.3mm;
   background: var(--brand);
 }

 .cover-meta {
   align-items: stretch;
 }

 .meta-card {
   flex: 1 1 0;
   border-top: 1px solid var(--brand);
   border-bottom: 1px solid var(--line);
   padding: 3mm 0 3.5mm;
 }

 .meta-value {
   display: block;
   margin-top: 1.5mm;
   font-size: 11pt;
   color: #202020;
   font-weight: 700;
 }

 .content {
   padding-top: 11mm;
   padding-bottom: 13mm;
   display: grid;
   gap: 5mm;
 }

 .two-col {
   display: grid;
   grid-template-columns: 1fr 1fr;
   gap: 6mm;
   align-items: start;
 }

 .box {
   border: 1px solid var(--line);
   padding: 4mm 4.5mm;
   background: #fff;
 }

 .box.soft {
   background: var(--brand-faint);
 }

 table {
   width: 100%;
   border-collapse: collapse;
 }

 .table th,
 .table td {
   border: 1px solid var(--line);
   padding: 2.3mm 2.5mm;
   vertical-align: top;
   text-align: left;
 }

 .table th {
   background: var(--brand-soft);
   color: var(--brand);
   font-size: 8.3pt;
   text-transform: uppercase;
   letter-spacing: 0.03em;
 }

 .table td {
   font-size: 9.4pt;
   line-height: 1.3;
 }

 .table td.num,
 .table td.center {
   text-align: center;
   white-space: nowrap;
 }

 .table td.sum {
   text-align: right;
   white-space: nowrap;
   font-weight: 700;
 }

 .small {
   font-size: 8.8pt;
   color: var(--muted);
   line-height: 1.35;
 }

 .abbr-grid {
   display: grid;
   grid-template-columns: 18mm 1fr;
   gap: 2mm 3mm;
   border: 1px solid var(--line);
   background: #fbfcff;
   padding: 4mm 4.5mm;
 }

 .abbr-grid strong {
   color: var(--brand);
   font-size: 9pt;
 }

 .abbr-grid span {
   font-size: 9pt;
   line-height: 1.28;
 }

 .summary-panel {
   border: 1px solid var(--brand);
   background: linear-gradient(180deg, #f7fbff 0%, #edf4fb 100%);
   padding: 5mm 5.5mm;
 }

 .summary-panel .big {
   display: block;
   font-size: 18pt;
   line-height: 1;
   color: var(--brand);
   font-weight: 700;
   margin: 2mm 0 1.5mm;
 }

 .cost-lines {
   display: grid;
   gap: 2mm;
   margin-top: 3mm;
 }

 .cost-line {
   display: flex;
   justify-content: space-between;
   gap: 4mm;
   border-bottom: 1px solid var(--line);
   padding-bottom: 1.6mm;
   font-size: 9.4pt;
 }

 .cost-line strong {
   color: #202020;
 }

 .link-list a {
   color: var(--brand);
   text-decoration: none;
   word-break: break-word;
 }

 .emphasis {
   color: var(--brand);
   font-weight: 700;
 }

 @media print {
   body {
     background: #fff;
     padding: 0;
   }

   .document {
     width: auto;
   }

   .page {
     margin: 0;
     box-shadow: none;
   }
 }

 @media (max-width: 900px) {
   body {
     padding: 0;
     background: #fff;
   }

   .document,
   .page {
     width: 100%;
   }

   .page {
     min-height: auto;
     margin-bottom: 0;
     box-shadow: none;
   }

   .page-inner {
     min-height: auto;
     padding: 24px 18px 42px;
   }

   .cover-company,
   .two-col,
   .cover-meta,
   .cover-signature,
   .contact-row {
     grid-template-columns: 1fr;
     flex-direction: column;
   }

   .recipient-card {
     width: 100%;
     align-self: stretch;
   }
 }
